import { CustomAttribute as CustomAttributeModel } from '@/checkout/data/models/custom-attribute';
import { AttributeValue } from '@/checkout/__generated__/types';

const isAttributeValue = (attribute: any): attribute is AttributeValue => {
  if (!attribute) return false;
  return 'code' in attribute && 'value' in attribute;
};

export const transformCustomAttributes = (
  data: Array<AttributeValue | any | null> | null | undefined
): CustomAttributeModel[] => {
  if (!data) return [];
  return data.filter(isAttributeValue).map((attribute) => {
    const { code, value } = attribute;
    return { code, value };
  });
};
