import { Cart, NegotiableQuote } from '@/checkout/data/models';
import {
  computed,
  ReadonlySignal,
  signal,
} from '@adobe-commerce/elsie/lib/signals';
import { events } from '@adobe-commerce/event-bus';

export enum QueueName {
  Updates = 'updates',
  Default = 'default',
  ShippingEstimate = 'shippingEstimate',
}

type Request<T> = () => Promise<T>;
type QueueCompletedHandler<T> = (result: T) => void;

interface QueuedRequest<T> {
  requestFn: Request<T>;
  resolve: (value: T) => void;
  reject: (error: any) => void;
}

const queues = new Map<QueueName, QueuedRequest<any>[]>();
const processing = new Map<QueueName, boolean>();
const pendingRequests = signal<Set<QueueName>>(new Set());
const onQueueCompleted = new Map<QueueName, QueueCompletedHandler<any>>();

onQueueCompleted.set(
  QueueName.Updates,
  (latestResult: Cart | NegotiableQuote) => {
    events.emit('checkout/updated', latestResult);
  }
);

async function processQueue(type: QueueName): Promise<void> {
  processing.set(type, true);

  const queue = queues.get(type)!;
  let latestSuccessResult: any;

  while (queue.length > 0) {
    const request = queue.shift()!;

    try {
      const result = await request.requestFn();
      request.resolve(result);
      latestSuccessResult = result;
    } catch (error) {
      request.reject(error);
    }
  }

  processing.set(type, false);

  const pendingSet = new Set(pendingRequests.value);
  pendingSet.delete(type);
  pendingRequests.value = pendingSet;

  const handler = onQueueCompleted.get(type);

  if (handler && latestSuccessResult) {
    handler(latestSuccessResult);
  }
}

export function enqueueRequest<T>(
  requestFn: Request<T>,
  name: QueueName = QueueName.Default
): Promise<T> {
  if (!queues.has(name)) {
    queues.set(name, []);
  }

  const queue = queues.get(name)!;

  const promise = new Promise<T>((resolve, reject) => {
    queue.push({ requestFn, resolve, reject });
  });

  const pendingSet = new Set(pendingRequests.value);
  pendingSet.add(name);
  pendingRequests.value = pendingSet;

  if (!processing.get(name)) {
    processQueue(name);
  }

  return promise;
}

export const hasPendingUpdates: ReadonlySignal<boolean> = computed(() => {
  return pendingRequests.value.has(QueueName.Updates);
});

export const hasPendingShippingEstimate: ReadonlySignal<boolean> = computed(
  () => {
    return pendingRequests.value.has(QueueName.ShippingEstimate);
  }
);
