import { config } from '@/checkout/api';
import { Cart as CartModel } from '@/checkout/data/models';
import {
  transformAvailablePaymentMethods,
  transformSelectedPaymentMethod,
} from '@/checkout/data/transforms/transform-payment-methods';
import { GetCartQuery } from '@/checkout/__generated__/types';
import { merge } from '@adobe-commerce/elsie/lib';

import {
  transformCartBillingAddress,
  transformCartShippingAddress,
} from '@/checkout/data/transforms/transform-cart-address';
import { state } from '@/checkout/lib/state';

type Cart = GetCartQuery['cart'];

const transformCart = (data: Cart): CartModel | undefined => {
  if (!data) return;

  const model = {
    type: 'cart' as const,
    availablePaymentMethods: transformAvailablePaymentMethods(
      data.available_payment_methods
    ),
    billingAddress: transformCartBillingAddress(data.billing_address),
    email: data.email ?? undefined,
    id: data.id,
    isEmpty: data.total_quantity === 0,
    isVirtual: data.is_virtual,
    selectedPaymentMethod: transformSelectedPaymentMethod(
      data.selected_payment_method
    ),
    shippingAddresses: transformCartShippingAddress(data.shipping_addresses),
    isGuest: !state.authenticated,
  };

  // Extend the model merging custom transformer, if provided
  return merge(
    model, // default transformer
    config.getConfig().models?.CartModel?.transformer?.(data) // custom transformer
  );
};

export { Cart, transformCart };
