import {
  getCart,
  getNegotiableQuote,
  initializeCheckout,
  resetCheckout,
} from '@/checkout/api';
import { state } from '@/checkout/lib/state';
import { isCartInput, SynchronizeInput } from '@/checkout/types';
import { events } from '@adobe-commerce/event-bus';

const getSynchronizedData = async (input: NonNullable<SynchronizeInput>) => {
  try {
    if (isCartInput(input)) {
      state.cartId = input.id;
      state.quoteId = null;
      return (await getCart()) ?? null;
    }
    state.cartId = null;
    state.quoteId = input.uid;
    return (await getNegotiableQuote()) ?? null;
  } catch (error) {
    console.error('Checkout synchronization failed:', error);
    return null;
  }
};

export const synchronizeCheckout = async (data: SynchronizeInput) => {
  if (!state.initialized) return initializeCheckout(data);

  if (data === null) {
    resetCheckout();
    return;
  }

  const update = await getSynchronizedData(data);

  events.emit('checkout/updated', update);
};
