import {
  AgreementMode,
  CheckoutAgreement as CheckoutAgreementModel,
} from '@/checkout/data/models';
import { Get_Checkout_AgreementsQuery } from '@/checkout/__generated__/types';

type CheckoutAgreements = Get_Checkout_AgreementsQuery['checkoutAgreements'];
type FilteredAgreement = NonNullable<NonNullable<CheckoutAgreements>[0]>;

export const transformCheckoutAgreements = (
  data: CheckoutAgreements
): CheckoutAgreementModel[] => {
  if (!data) return [];

  return data
    .filter((agreement): agreement is FilteredAgreement => !!agreement)
    .map((agreement) => ({
      id: agreement.agreement_id,
      name: agreement.name,
      mode: AgreementMode[agreement.mode],
      text: agreement.checkbox_text,
      content: {
        value: agreement.content,
        html: agreement.is_html,
        height: agreement.content_height ?? null,
      },
    }));
};
