import {
  AddressInput as AddressInputModel,
  CartAddress as CartAddressModel,
  CartShippingAddress as CartShippingAddressModel,
} from '@/checkout/data/models';

import {
  transformAddressCountry,
  transformAddressRegion,
  transformCustomAttributes,
  transformSelectedShippingMethod,
  transformShippingMethods,
} from '@/checkout/data/transforms';

import { GetCartQuery } from '@/checkout/__generated__/types';

type ShippingAddresses = NonNullable<
  GetCartQuery['cart']
>['shipping_addresses'];
type CartShippingAddress = ShippingAddresses[0];
type NonNullableShippingAddress = NonNullable<CartShippingAddress>;

type CartBillingAddress = NonNullable<GetCartQuery['cart']>['billing_address'];
type NonNullableBillingAddress = NonNullable<CartBillingAddress>;

const transformBaseCartAddress = (
  data: NonNullableShippingAddress | NonNullableBillingAddress
): CartAddressModel => {
  const street = data.street.filter(Boolean) as string[];

  return {
    city: data.city,
    company: data.company || undefined,
    country: transformAddressCountry(data.country),
    customAttributes: transformCustomAttributes(data.custom_attributes),
    fax: data.fax || undefined,
    firstName: data.firstname,
    id: data?.id || undefined,
    lastName: data.lastname,
    middleName: data.middlename || undefined,
    postCode: data.postcode || undefined,
    prefix: data.prefix || undefined,
    region: transformAddressRegion(data.region),
    street,
    suffix: data.suffix || undefined,
    telephone: data.telephone || undefined,
    uid: data.uid,
    vatId: data.vat_id || undefined,
  };
};

const transformCartBillingAddress = (
  data: CartBillingAddress
): CartAddressModel | undefined => {
  if (!data) return;
  return transformBaseCartAddress(data);
};

const transformCartShippingAddress = (
  data: ShippingAddresses
): CartShippingAddressModel[] => {
  return data
    .filter((address) => !!address)
    .map((address) => {
      const {
        available_shipping_methods,
        selected_shipping_method,
        same_as_billing,
        ...baseData
      } = address as NonNullableShippingAddress;

      return {
        ...transformBaseCartAddress(baseData as NonNullableShippingAddress),
        availableShippingMethods: transformShippingMethods(
          available_shipping_methods
        ),
        selectedShippingMethod: transformSelectedShippingMethod(
          selected_shipping_method
        ),
        sameAsBilling: same_as_billing,
      };
    });
};

const transformAddressToCartAddressInput = <T extends CartAddressModel>(
  address?: T | null
): AddressInputModel | undefined => {
  if (!address) return;
  return {
    city: address.city,
    company: address.company,
    countryCode: address.country.code,
    customAttributes: address.customAttributes || [],
    firstName: address.firstName,
    lastName: address.lastName,
    postcode: address.postCode,
    region: address.region?.code,
    regionId: address.region?.id,
    street: address.street,
    telephone: address.telephone,
    vatId: address.vatId,
    prefix: address.prefix,
    suffix: address.suffix,
    middleName: address.middleName,
    fax: address.fax,
  };
};

export {
  CartBillingAddress,
  CartShippingAddress,
  transformAddressToCartAddressInput,
  transformCartBillingAddress,
  transformCartShippingAddress,
};
