import { NegotiableQuote as NegotiableQuoteModel } from '@/checkout/data/models/';
import { GetNegotiableQuoteQuery } from '@/checkout/__generated__/types';

import {
  transformAvailablePaymentMethods,
  transformQuoteBillingAddress,
  transformQuoteShippingAddress,
  transformSelectedPaymentMethod,
} from '@/checkout/data/transforms';

type NegotiableQuote = GetNegotiableQuoteQuery['negotiableQuote'];

export const transformNegotiableQuote = (
  data: NegotiableQuote | undefined
): NegotiableQuoteModel | null => {
  if (!data) return null;

  return {
    type: 'quote' as const,
    availablePaymentMethods: transformAvailablePaymentMethods(
      data.available_payment_methods
    ),
    billingAddress: transformQuoteBillingAddress(data.billing_address),
    email: data.email ?? '',
    isEmpty: data.total_quantity === 0,
    isVirtual: data.is_virtual,
    name: data.name,
    selectedPaymentMethod: transformSelectedPaymentMethod(
      data.selected_payment_method
    ),
    shippingAddresses: transformQuoteShippingAddress(data.shipping_addresses),
    status: data.status,
    uid: data.uid,
  };
};
