import { fetchGraphQl, FetchOptions, FetchQueryError } from '@/checkout/api';
import { enqueueRequest, QueueName } from '@/checkout/lib/enqueueRequest';
import { filterControlledErrors } from '@/checkout/lib/filterControlledErrors';
import { FetchError } from '@/checkout/lib/errors';

type DispatchApiCallParams<T> = {
  defaultValueOnFail?: T;
  options?: FetchOptions;
  path: string;
  query: string;
  queueName?: QueueName;
  transformer?: (data: any) => T;
  type: 'query' | 'mutation';
};

export function getValueAtPath(obj: any, path: string) {
  return path
    .split('.')
    .reduce(
      (acc, part) => (acc && acc[part] !== undefined ? acc[part] : undefined),
      obj
    );
}

async function dispatchApiCall<T>(
  params: DispatchApiCallParams<T>
): Promise<T> {
  const {
    defaultValueOnFail,
    options,
    path,
    query,
    queueName,
    transformer,
    type,
  } = params;

  try {
    const processApiCall = async () => {
      const { data, errors } = await fetchGraphQl<T>(query, {
        method: type === 'query' ? 'GET' : 'POST',
        cache: type === 'query' ? 'no-cache' : undefined,
        ...options,
      });

      if (errors) {
        const uncontrolledErrors = filterControlledErrors(errors);

        if (uncontrolledErrors.length > 0) {
          throw new FetchError(uncontrolledErrors as FetchQueryError);
        }
      }

      let result = getValueAtPath(data, path);

      if (result === undefined) {
        throw new Error(`No data found at path: ${path}`);
      }

      return transformer ? transformer(result) : result;
    };

    // Execute the API call, either directly or through the queue
    const result =
      type === 'mutation'
        ? await enqueueRequest<T>(processApiCall, queueName)
        : await processApiCall();

    return result;
  } catch (error: any) {
    if (defaultValueOnFail !== undefined) return defaultValueOnFail;
    throw error;
  }
}

export { dispatchApiCall };
