import { CheckoutAgreement } from '@/checkout/data/models';
import { transformCheckoutAgreements } from '@/checkout/data/transforms';
import { dispatchApiCall } from '@/checkout/lib';
import { GET_CHECKOUT_AGREEMENTS } from './graphql/getCheckoutAgreements.graphql';

export const getCheckoutAgreements = async (): Promise<CheckoutAgreement[]> => {
  return await dispatchApiCall({
    defaultValueOnFail: [],
    options: { method: 'GET', cache: 'no-cache' },
    path: 'checkoutAgreements',
    query: GET_CHECKOUT_AGREEMENTS,
    transformer: transformCheckoutAgreements,
    type: 'query',
  });
};
