import { config } from '@/checkout/api';
import { Customer as CustomerModel } from '@/checkout/data/models';
import { GetCustomerQuery } from '@/checkout/__generated__/types';
import { merge } from '@adobe-commerce/elsie/lib';

type Customer = GetCustomerQuery['customer'];

const transformCustomer = (data: Customer): CustomerModel | null => {
  if (!data) return null;

  const model = {
    firstName: data.firstname || '',
    lastName: data.lastname || '',
    email: data.email || '',
  };

  // Extend the model merging custom transformer, if provided
  return merge(
    model, // default transformer
    config.getConfig().models?.CustomerModel?.transformer?.(data) // custom transformer
  );
};

export { Customer, transformCustomer };
