import { ESTIMATE_SHIPPING_METHOD_FRAGMENT } from '@/checkout/api/graphql/ShippingMethodFragment.graphql';

export const estimateShippingMethodsMutation = /* GraphQL */ `
  mutation estimateShippingMethods(
    $cartId: String!
    $address: EstimateAddressInput!
  ) {
    estimateShippingMethods(input: { cart_id: $cartId, address: $address }) {
      ...ESTIMATE_SHIPPING_METHOD_FRAGMENT
    }
  }

  ${ESTIMATE_SHIPPING_METHOD_FRAGMENT}
`;
