import { ShippingMethod } from '@/checkout/data/models/shipping-method';
import { GetCartQuery } from '@/checkout/__generated__/types';

type Cart = NonNullable<GetCartQuery['cart']>;
type ShippingAddresses = Cart['shipping_addresses'];
type ShippingAddress = NonNullable<NonNullable<ShippingAddresses>[number]>;
type AvailableShippingMethods = ShippingAddress['available_shipping_methods'];
type AvailableShippingMethod = NonNullable<AvailableShippingMethods>[number];
type SelectedShippingMethod = ShippingAddress['selected_shipping_method'];

type FilteredShippingMethod = Omit<
  NonNullable<AvailableShippingMethod>,
  | 'method_code'
  | 'method_title'
  | 'amount'
  | 'price_excl_tax'
  | 'price_incl_tax'
> & {
  method_code: string;
  method_title: string;
  amount: {
    value: number;
    currency: string;
  };
  price_excl_tax: {
    value: number;
    currency: string;
  };
  price_incl_tax: {
    value: number;
    currency: string;
  };
};

const byPrice = (a: ShippingMethod, b: ShippingMethod) =>
  a.amount.value - b.amount.value;

export const isNullish = (value: any): boolean =>
  value === null || value === undefined;

const isValid = (method: AvailableShippingMethod | SelectedShippingMethod) => {
  if (!method) return false;
  if (!method.method_code || !method.method_title) return false;
  if (isNullish(method.amount.value) || !method.amount.currency) return false;
  return true;
};

const buildShippingMethod = (data: FilteredShippingMethod): ShippingMethod => {
  return {
    amount: {
      value: data.amount.value,
      currency: data.amount.currency,
    },
    title: data.method_title,
    code: data.method_code,
    carrier: {
      code: data.carrier_code,
      title: data.carrier_title,
    },
    value: `${data.carrier_code} - ${data.method_code}`,
    ...(data.price_excl_tax && {
      amountExclTax: {
        value: data.price_excl_tax.value,
        currency: data.price_excl_tax.currency,
      },
    }),
    ...(data.price_incl_tax && {
      amountInclTax: {
        value: data.price_incl_tax.value,
        currency: data.price_incl_tax.currency,
      },
    }),
    ...((data as any).original_amount && {
      originalAmount: {
        value: (data as any).original_amount.value,
        currency: (data as any).original_amount.currency,
      },
    }),
  };
};

export const transformSelectedShippingMethod = (
  data: SelectedShippingMethod
): ShippingMethod | undefined => {
  if (!isValid(data)) return;
  return buildShippingMethod(data as FilteredShippingMethod);
};

export const transformAvailableShippingMethod = (
  data: AvailableShippingMethod
): ShippingMethod | undefined => {
  if (!isValid(data)) return;
  return buildShippingMethod(data as FilteredShippingMethod);
};

export const transformShippingMethods = (
  data: AvailableShippingMethods
): ShippingMethod[] => {
  if (!data) return [];

  return data
    .filter(isValid)
    .map((method) => buildShippingMethod(method as FilteredShippingMethod))
    .sort(byPrice);
};
