import {
  CartModel,
  InitializeInput,
  NegotiableQuoteModel,
  SynchronizeInput,
} from '@/checkout/types';

export const isCartInput = (
  input: NonNullable<InitializeInput | SynchronizeInput>
): input is CartModel => {
  return 'id' in input;
};

export const isNegotiableQuoteInput = (
  input: NonNullable<InitializeInput | SynchronizeInput>
): input is NegotiableQuoteModel => {
  return 'uid' in input;
};
