import {
  AddressInput as AddressInputModel,
  BillingAddressInput as BillingAddressInputModel,
  PaymentMethodInput as PaymentMethodInputModel,
  ShippingAddressInput as ShippingAddressInputModel,
  ShippingMethodInput as ShippingMethodInputModel,
} from '@/checkout/data/models/api';

import {
  BillingAddressInput,
  NegotiableQuoteBillingAddressInput,
  NegotiableQuotePaymentMethodInput,
  NegotiableQuoteShippingAddressInput,
  PaymentMethodInput,
  ShippingAddressInput,
  ShippingMethodInput,
} from '@/checkout/__generated__/types';

export function transformPaymentMethodInputModelToCartInput({
  code,
  ...additionalData
}: PaymentMethodInputModel): PaymentMethodInput {
  return {
    code,
    ...additionalData,
  };
}

export function transformPaymentMethodInputModelToQuoteInput({
  code,
  ...additionalData
}: PaymentMethodInputModel): NegotiableQuotePaymentMethodInput {
  return {
    code,
    ...additionalData,
  };
}

export const transformShippingMethodInput = (
  input: ShippingMethodInputModel | ShippingMethodInput
): ShippingMethodInput => {
  if ('carrier_code' in input && 'method_code' in input) {
    return input as ShippingMethodInput;
  }

  // Transform from model format to GraphQL format
  const modelInput = input as ShippingMethodInputModel;

  const { carrierCode, methodCode, ...additionalData } = modelInput;

  return {
    carrier_code: carrierCode,
    method_code: methodCode,
    ...additionalData,
  };
};

export function transformShippingMethodsInputModel(
  input: Array<ShippingMethodInputModel | ShippingMethodInput>
): Array<ShippingMethodInput> {
  return input.map(transformShippingMethodInput);
}

function transformAddressInputModel(address: AddressInputModel) {
  return {
    fax: address.fax,
    middlename: address.middleName,
    prefix: address.prefix,
    suffix: address.suffix,
    vat_id: address.vatId,
    city: address.city,
    custom_attributes:
      address.customAttributes?.map((attribute: any) => ({
        attribute_code: attribute.code,
        value: attribute.value,
      })) || [],
    company: address.company,
    country_code: address.countryCode,
    firstname: address.firstName,
    lastname: address.lastName,
    postcode: address.postcode,
    region: address.region,
    region_id: address.regionId,
    save_in_address_book: address.saveInAddressBook,
    street: address.street,
    telephone: address.telephone,
  };
}

export function transformShippingAddressInputModelToCartInput(
  input: ShippingAddressInputModel
): ShippingAddressInput {
  const { customerAddressId, pickupLocationCode, address } = input;

  const result: ShippingAddressInput = {};

  if (customerAddressId) {
    return { customer_address_id: customerAddressId };
  }

  if (pickupLocationCode) {
    result.pickup_location_code = pickupLocationCode;
  }

  if (!pickupLocationCode && address) {
    result.address = transformAddressInputModel(address);
  }

  return result;
}

export function transformShippingAddressInputModelToQuoteInput(
  input: ShippingAddressInputModel
): NegotiableQuoteShippingAddressInput {
  const { customerAddressUid, address } = input;

  const result: NegotiableQuoteShippingAddressInput = {};

  if (customerAddressUid) {
    return { customer_address_uid: customerAddressUid };
  }

  if (address) {
    result.address = transformAddressInputModel(address);
  }

  return result;
}

export function transformBillingAddressInputModelToCartInput(
  input: BillingAddressInputModel
): BillingAddressInput {
  const {
    customerAddressId,
    sameAsShipping = false,
    useForShipping = false,
    address,
  } = input;

  let result: BillingAddressInput = {
    use_for_shipping: useForShipping,
    same_as_shipping: sameAsShipping,
  };

  if (!sameAsShipping && customerAddressId) {
    result.customer_address_id = customerAddressId;
    return result;
  }

  if (!sameAsShipping && address) {
    result.address = transformAddressInputModel(address);
  }

  return result;
}

export function transformBillingAddressInputModelToQuoteInput(
  input: BillingAddressInputModel
): NegotiableQuoteBillingAddressInput {
  const {
    customerAddressUid,
    sameAsShipping = false,
    useForShipping = false,
    address,
  } = input;

  let result: NegotiableQuoteBillingAddressInput = {
    use_for_shipping: useForShipping,
    same_as_shipping: sameAsShipping,
  };

  if (!sameAsShipping && customerAddressUid) {
    result.customer_address_uid = customerAddressUid;
    return result;
  }

  if (!sameAsShipping && address) {
    result.address = transformAddressInputModel(address);
  }

  return result;
}
