import { Region as RegionModel } from '@/checkout/data/models';
import {
  CartAddressRegion,
  NegotiableQuoteAddressRegion,
} from '@/checkout/__generated__/types';

type AddressRegion = CartAddressRegion | NegotiableQuoteAddressRegion;
type OptionalAddressRegion = AddressRegion | undefined | null;

export const transformAddressRegion = (
  data: OptionalAddressRegion
): RegionModel | undefined => {
  if (!data?.code || !data?.label) return;
  return {
    code: data.code,
    name: data.label,
    id: data.region_id ?? undefined,
  };
};
