import { getNegotiableQuoteQuery } from '@/checkout/api/getNegotiableQuote/graphql';
import { transformNegotiableQuote as transformer } from '@/checkout/data/transforms';
import { state } from '@/checkout/lib';
import { dispatchApiCall } from '@/checkout/lib/dispatchApiCall';
import {
  MissingNegotiableQuoteId,
  Unauthenticated,
} from '@/checkout/lib/errors';

type GetNegotiableQuoteInput = {
  uid?: string;
};

export const getNegotiableQuote = async (
  input: GetNegotiableQuoteInput = {}
) => {
  const quoteId = input.uid ?? state.quoteId;
  const isGuest = state.authenticated === false;

  if (isGuest) throw new Unauthenticated();
  if (!quoteId) throw new MissingNegotiableQuoteId();

  const variables = { quoteId };

  return await dispatchApiCall({
    type: 'query',
    query: getNegotiableQuoteQuery,
    options: { method: 'GET', cache: 'no-cache', variables },
    path: 'negotiableQuote',
    transformer,
  });
};
