import { StoreConfig, TaxDisplay } from '@/checkout/data/models';
import { transformStoreConfig } from '@/checkout/data/transforms';
import { dispatchApiCall, state } from '@/checkout/lib';
import { getStoreConfigQuery } from './graphql/getStoreConfig.graphql';

export const DEFAULT_COUNTRY = 'US';

export const STORE_CONFIG_DEFAULTS: StoreConfig = {
  defaultCountry: DEFAULT_COUNTRY,
  agreementsEnabled: true,
  shoppingCartDisplaySetting: {
    shipping: TaxDisplay.EXCLUDING_TAX,
  },
};

export const getStoreConfig = async () => {
  return await dispatchApiCall({
    defaultValueOnFail: STORE_CONFIG_DEFAULTS,
    options: { method: 'GET', cache: 'no-cache' },
    path: 'storeConfig',
    query: getStoreConfigQuery,
    transformer: transformStoreConfig,
    type: 'query',
  });
};

export const getStoreConfigCache = () => state.config;
