import {
  Address as AddressModel,
  ShippingAddress as ShippingAddressModel,
} from '@/checkout/data/models';

import {
  transformAddressCountry,
  transformAddressRegion,
  transformCustomAttributes,
  transformSelectedShippingMethod,
  transformShippingMethods,
} from '@/checkout/data/transforms';
import { GetNegotiableQuoteQuery } from '@/checkout/__generated__/types';

type QuoteShippingAddresses = NonNullable<
  GetNegotiableQuoteQuery['negotiableQuote']
>['shipping_addresses'];
type QuoteShippingAddress = QuoteShippingAddresses[0];
type NonNullableShippingAddress = NonNullable<QuoteShippingAddress>;

type QuoteBillingAddress = NonNullable<
  GetNegotiableQuoteQuery['negotiableQuote']
>['billing_address'];
type NonNullableBillingAddress = NonNullable<QuoteBillingAddress>;

const transformAddress = (
  data: NonNullableShippingAddress | NonNullableBillingAddress
): AddressModel => {
  const street = data.street.filter(Boolean) as string[];

  return {
    city: data.city,
    company: data.company || undefined,
    country: transformAddressCountry(data.country),
    customAttributes: transformCustomAttributes(data.custom_attributes),
    customerAddressUid: data.customer_address_uid || undefined,
    fax: data.fax || undefined,
    firstName: data.firstname,
    lastName: data.lastname,
    middleName: data.middlename || undefined,
    postCode: data.postcode || undefined,
    prefix: data.prefix || undefined,
    region: transformAddressRegion(data.region),
    street,
    suffix: data.suffix || undefined,
    telephone: data.telephone || undefined,
    uid: data.uid,
    vatId: data.vat_id || undefined,
  };
};

const transformQuoteBillingAddress = (
  data: QuoteBillingAddress
): AddressModel | undefined => {
  if (!data) return;
  return transformAddress(data);
};

const transformQuoteShippingAddress = (
  data: QuoteShippingAddresses
): ShippingAddressModel[] => {
  return data
    .filter((address) => !!address)
    .map((address) => {
      const {
        available_shipping_methods,
        selected_shipping_method,
        ...baseData
      } = address as NonNullableShippingAddress;

      return {
        ...transformAddress(baseData as NonNullableShippingAddress),
        availableShippingMethods: transformShippingMethods(
          available_shipping_methods
        ),
        selectedShippingMethod: transformSelectedShippingMethod(
          selected_shipping_method
        ),
      };
    });
};

export {
  QuoteBillingAddress,
  QuoteShippingAddress,
  transformQuoteBillingAddress,
  transformQuoteShippingAddress,
};
