import { setGuestEmailMutation } from '@/checkout/api/setGuestEmailOnCart/graphql/setGuestEmailOnCart.graphql';
import { transformCart } from '@/checkout/data/transforms';
import { dispatchApiCall } from '@/checkout/lib/dispatchApiCall';
import { QueueName } from '@/checkout/lib/enqueueRequest';
import { MissingCart } from '@/checkout/lib/errors';
import { state } from '@/checkout/lib/state';

export const setGuestEmailOnCart = async (email: string) => {
  const cartId = state.cartId;

  if (!cartId) throw new MissingCart();

  return await dispatchApiCall({
    options: { variables: { cartId, email } },
    path: 'setGuestEmailOnCart.cart',
    query: setGuestEmailMutation,
    queueName: QueueName.Updates,
    transformer: transformCart,
    type: 'mutation',
  });
};
