import { FetchQueryError } from '@/checkout/api/fetch-graphql';

export class FetchError extends Error {
  constructor(reasons: FetchQueryError) {
    super(reasons.map((e: any) => e.message).join(' '));
    this.name = 'FetchError';
  }
}

export class InvalidInput extends Error {
  constructor(message: string) {
    super(message);
    this.name = 'InvalidInput';
  }
}

export class MissingArgument extends InvalidInput {
  constructor(argumentName: string) {
    super(`${argumentName} is required.`);
  }
}

export class MissingCart extends MissingArgument {
  constructor() {
    super('Cart ID');
  }
}

export class MissingCartAndQuote extends InvalidInput {
  constructor() {
    super('Either Cart ID or Quote ID is required.');
  }
}

export class Unauthenticated extends Error {
  constructor() {
    super('User is not authenticated');
  }
}

export class MissingNegotiableQuoteId extends MissingArgument {
  constructor() {
    super('Negotiable Quote ID');
  }
}

export class MissingEmail extends MissingArgument {
  constructor() {
    super('Email');
  }
}

export class MissingPaymentMethod extends MissingArgument {
  constructor() {
    super('Payment method code');
  }
}

export class MissingShippingAddress extends MissingArgument {
  constructor() {
    super('Shipping address');
  }
}

export class MissingShippingMethod extends MissingArgument {
  constructor() {
    super('Shipping method');
  }
}

export class MissingBillingAddress extends MissingArgument {
  constructor() {
    super('Billing address');
  }
}

export class MissingCountry extends MissingArgument {
  constructor() {
    super('Country Code');
  }
}
