import {
  getCartQuery,
  getCustomerCartQuery,
} from '@/checkout/api/getCart/graphql';
import { transformCart } from '@/checkout/data/transforms';
import { dispatchApiCall } from '@/checkout/lib/dispatchApiCall';
import { state } from '@/checkout/lib';
import { MissingCart } from '@/checkout/lib/errors';

export const getCart = async () => {
  const cartId = state.cartId;
  const isGuest = state.authenticated === false;
  const query = isGuest ? getCartQuery : getCustomerCartQuery;
  const variables = isGuest ? { cartId } : {};

  if (isGuest && !cartId) throw new MissingCart();

  return await dispatchApiCall({
    type: 'query',
    query,
    options: { method: 'POST', cache: 'no-cache', variables },
    path: 'cart',
    transformer: transformCart,
  });
};
