import { StoreConfig } from '@/checkout/data/models';

type State = {
  authenticated: boolean;
  cartId?: string | null;
  config: StoreConfig | null;
  initialized: boolean;
  quoteId?: string | null;
};

const _state: State = (() => ({
  authenticated: false,
  cartId: null,
  config: null,
  initialized: false,
  quoteId: null,
}))();

// Proxy state to allow reactivity
export const state = new Proxy(_state, {
  set(target, key, value) {
    // @ts-ignore
    target[key] = value;
    return true;
  },
  get(target, key) {
    return target[key as keyof State];
  },
});

export function isQuoteCheckout(): boolean {
  return state.quoteId !== null;
}

export function isCartCheckout(): boolean {
  return state.cartId !== null;
}
