import { InvalidInput, Unauthenticated } from './customErrors';

export type ErrorCode = string;

export enum ErrorCodes {
  INVALID_INPUT = 'INVALID_INPUT',
  SERVER_ERROR = 'SERVER_ERROR',
  UNAUTHENTICATED = 'UNAUTHENTICATED',
  UNKNOWN_ERROR = 'UNKNOWN_ERROR',
  QUOTE_DATA_ERROR = 'QUOTE_DATA_ERROR',
  QUOTE_PERMISSION_DENIED = 'QUOTE_PERMISSION_DENIED',
  PERMISSION_DENIED = 'PERMISSION_DENIED',
}

const KNOWN_SERVER_ERRORS = ['PlaceOrderError'];

export interface ErrorClassifier {
  /**
   * The specific code to return if this classifier matches.
   */
  code: ErrorCode;
  /**
   * A function that returns `true` if it recognizes the error.
   * It must safely handle `unknown` inputs.
   */
  matches: (error: unknown) => boolean;
}

// Array of all known error classifiers.
// The order is important! The first one to match will be used.
export const classifiers: ErrorClassifier[] = [
  {
    code: ErrorCodes.INVALID_INPUT,
    matches: (error: unknown): boolean => {
      return error instanceof InvalidInput;
    },
  },
  {
    code: ErrorCodes.UNAUTHENTICATED,
    matches: (error: unknown): boolean => {
      return error instanceof Unauthenticated;
    },
  },
  {
    code: ErrorCodes.SERVER_ERROR,
    matches: (error: unknown): boolean => {
      if (!error || typeof error !== 'object' || !('name' in error)) {
        return false;
      }

      return KNOWN_SERVER_ERRORS.includes((error as { name: string }).name);
    },
  },
];
