import { PaymentMethod } from '@/checkout/data/models/payment-method';
import { GetCartQuery } from '@/checkout/__generated__/types';

type SelectedPaymentMethod = NonNullable<
  GetCartQuery['cart']
>['selected_payment_method'];

type AvailablePaymentMethods = NonNullable<
  GetCartQuery['cart']
>['available_payment_methods'];

type AvailablePaymentMethod = NonNullable<AvailablePaymentMethods>[number];

type NonNullabePaymentMethod = NonNullable<AvailablePaymentMethod>;

const transformSelectedPaymentMethod = (
  data: SelectedPaymentMethod
): PaymentMethod | undefined => {
  if (!data) return;
  const { code, title, ...additionalData } = data;
  return { code, title, additionalData };
};

const transformAvailablePaymentMethods = (
  data: AvailablePaymentMethods
): PaymentMethod[] | undefined => {
  if (!data) return;

  return data
    .filter((method) => !!method)
    .map((method) => {
      const { code, title, ...additionalData } =
        method as NonNullabePaymentMethod;
      return { code, title, additionalData };
    });
};

export { transformAvailablePaymentMethods, transformSelectedPaymentMethod };
