import { getCustomerQuery } from '@/checkout/api/getCustomer/graphql/getCustomer.graphql';
import { Customer } from '@/checkout/data/models';
import { transformCustomer } from '@/checkout/data/transforms';
import { dispatchApiCall } from '@/checkout/lib/dispatchApiCall';
import { state } from '@/checkout/lib/state';

export const getCustomer = async (): Promise<Customer | null> => {
  if (!state.authenticated) return null;

  return await dispatchApiCall({
    options: { method: 'GET', cache: 'no-cache' },
    path: 'customer',
    query: getCustomerQuery,
    transformer: transformCustomer,
    type: 'query',
  });
};
