import {
  getCart,
  getNegotiableQuote,
  getStoreConfig,
  synchronizeCheckout,
} from '@/checkout/api';
import { state } from '@/checkout/lib';
import { InitializeInput, isCartInput } from '@/checkout/types';
import { events } from '@adobe-commerce/event-bus';

const getInitialData = async (input: NonNullable<InitializeInput>) => {
  try {
    if (isCartInput(input)) {
      state.cartId = input.id;
      state.quoteId = null;
      return (await getCart()) ?? null;
    }
    state.cartId = null;
    state.quoteId = input.uid;
    return (await getNegotiableQuote()) ?? null;
  } catch (error) {
    console.error('Checkout initialization failed:', error);
    return null;
  }
};

export const initializeCheckout = async (input: InitializeInput) => {
  if (state.initialized) {
    await synchronizeCheckout(input);
    return;
  }

  if (!state.config) {
    state.config = await getStoreConfig();
  }

  const initialData = input ? await getInitialData(input) : null;

  state.initialized = true;
  events.emit('checkout/initialized', initialData);
};
