import {
  authenticateCustomer,
  ConfigProps,
  initializeCheckout,
  resetCheckout,
  synchronizeCheckout,
} from '@/checkout/api';
import { ErrorCodes } from '@/checkout/lib/errors';
import { PermissionsModel } from '@/checkout/types';
import { events, Events } from '@adobe-commerce/event-bus';

type Listener = [keyof Events, (...args: any[]) => void, { eager: boolean }?];

const asEager = { eager: true };

export const addCheckoutEventListeners = (config: ConfigProps | undefined) => {
  const useB2bQuotes = config?.features?.b2b?.quotes ?? false;

  const handleAuthenticated = (isAuthenticated = false) => {
    authenticateCustomer(isAuthenticated);

    if (!useB2bQuotes) return;
    if (isAuthenticated) return;

    const destination = config?.features?.b2b?.routeLogin?.();
    if (destination) {
      window.location.assign(destination);
    }
  };

  const cartListeners: Listener[] = [
    ['cart/initialized', initializeCheckout, asEager],
    ['cart/reset', resetCheckout],
    ['cart/updated', synchronizeCheckout],
    [
      'auth/permissions',
      (permissions: PermissionsModel) => {
        if (permissions['admin'] === true) return;

        if (!permissions['Magento_Sales::place_order']) {
          const message =
            config?.langDefinitions?.default?.Checkout?.ServerError
              ?.permissionDenied ||
            'You do not have permission to complete checkout. Please contact your administrator for assistance.';
          events.emit('checkout/error', {
            message,
            code: ErrorCodes.PERMISSION_DENIED,
          });
        }
      },
      asEager,
    ],
  ];

  const quoteListeners: Listener[] = [
    [
      'quote-management/quote-data/initialized',
      (data) => {
        if (!data.quote.canCheckout) {
          const message =
            config?.langDefinitions?.default?.Checkout?.Quote
              ?.permissionDenied ||
            'You do not have permission to checkout with this quote.';
          events.emit('checkout/error', {
            message,
            code: ErrorCodes.QUOTE_PERMISSION_DENIED,
          });
          return;
        }

        initializeCheckout(data.quote);
      },
      asEager,
    ],
    [
      'quote-management/quote-data/error',
      () => {
        const message =
          config?.langDefinitions?.default?.Checkout?.Quote?.dataError ||
          'We were unable to retrieve the quote data. Please try again later.';
        events.emit('checkout/error', {
          message,
          code: ErrorCodes.QUOTE_DATA_ERROR,
        });
      },
    ],
  ];

  const listeners: Listener[] = [
    ['authenticated', handleAuthenticated, asEager],
    ...(useB2bQuotes ? quoteListeners : cartListeners),
  ];

  return listeners.map(([eventName, handler, options]) => {
    return events.on(eventName, handler, options);
  });
};
