import { isEmailAvailableQuery } from '@/checkout/api/isEmailAvailable/graphql/isEmailAvailable.graphql';
import { EmailAvailability } from '@/checkout/data/models/email-availability';
import { transformEmailAvailability } from '@/checkout/data/transforms';
import { dispatchApiCall } from '@/checkout/lib/dispatchApiCall';
import { MissingEmail } from '@/checkout/lib/errors';

export const isEmailAvailable = async (
  email: string
): Promise<EmailAvailability> => {
  if (!email) throw new MissingEmail();

  return await dispatchApiCall({
    options: { method: 'GET', cache: 'no-cache', variables: { email } },
    path: 'isEmailAvailable',
    query: isEmailAvailableQuery,
    transformer: transformEmailAvailability,
    type: 'query',
  });
};
