import {
  setBillingAddressOnCartMutation,
  setBillingAddressOnQuoteMutation,
} from '@/checkout/api/setBillingAddress/graphql';
import { BillingAddressInput as BillingAddressInputModel } from '@/checkout/data/models';
import {
  transformBillingAddressInputModelToCartInput,
  transformBillingAddressInputModelToQuoteInput,
  transformCart,
  transformNegotiableQuote,
} from '@/checkout/data/transforms';
import { dispatchApiCall } from '@/checkout/lib/dispatchApiCall';
import { QueueName } from '@/checkout/lib/enqueueRequest';
import { InvalidInput, MissingBillingAddress } from '@/checkout/lib/errors';
import { ensureHasCartOrQuoteId } from '@/checkout/lib/guards';
import { state } from '@/checkout/lib/state';

const createBillingAddressSetter = <TTransformedInput, TTransformedOutput>(
  entityId: string,
  entityKey: string,
  mutation: string,
  transformer: (data: any) => TTransformedOutput,
  transformInput: (input: BillingAddressInputModel) => TTransformedInput,
  path: string
) => {
  return async (
    input: BillingAddressInputModel
  ): Promise<TTransformedOutput> => {
    return await dispatchApiCall({
      type: 'mutation',
      query: mutation,
      options: {
        variables: {
          [entityKey]: entityId,
          billingAddress: transformInput(input),
        },
      },
      path,
      queueName: QueueName.Updates,
      transformer,
    });
  };
};

const ensureIsValidCartInput = ({
  address,
  customerAddressId,
  customerAddressUid,
  sameAsShipping = false,
}: BillingAddressInputModel) => {
  if (!customerAddressId && customerAddressUid) {
    throw new InvalidInput('customerAddressUid is not supported');
  }

  if (!sameAsShipping && !customerAddressId && !address) {
    throw new MissingBillingAddress();
  }
};

const ensureIsValidQuoteInput = ({
  address,
  customerAddressId,
  customerAddressUid,
  sameAsShipping = false,
}: BillingAddressInputModel) => {
  if (!customerAddressUid && customerAddressId) {
    throw new InvalidInput('customerAddressId is not supported');
  }

  if (!sameAsShipping && !customerAddressUid && !address) {
    throw new MissingBillingAddress();
  }
};

const ensureIsValidInput = (input: BillingAddressInputModel) => {
  const isCart = Boolean(state.cartId);
  const isQuote = Boolean(state.quoteId);

  if (isCart) {
    ensureIsValidCartInput(input);
  } else if (isQuote) {
    ensureIsValidQuoteInput(input);
  }
};

export const setBillingAddress = async (input: BillingAddressInputModel) => {
  ensureHasCartOrQuoteId();
  ensureIsValidInput(input);

  const isCart = Boolean(state.cartId);

  const setter = isCart
    ? createBillingAddressSetter(
        state.cartId!,
        'cartId',
        setBillingAddressOnCartMutation,
        transformCart,
        transformBillingAddressInputModelToCartInput,
        'setBillingAddressOnCart.cart'
      )
    : createBillingAddressSetter(
        state.quoteId!,
        'quoteId',
        setBillingAddressOnQuoteMutation,
        transformNegotiableQuote,
        transformBillingAddressInputModelToQuoteInput,
        'setNegotiableQuoteBillingAddress.quote'
      );

  return await setter(input);
};
