import { addCheckoutEventListeners } from '@/checkout/api/initialize/listeners';
import {
  Cart as CartModel,
  Customer as CustomerModel,
  ShippingMethod,
} from '@/checkout/data/models';
import { state } from '@/checkout/lib';
import { Filter, Selector } from '@/checkout/types/utils';
import { definition } from '@adobe-commerce/elsie/i18n';
import { deepmerge, Initializer, Model } from '@adobe-commerce/elsie/lib';

const url = new URL(window.location.href);
const quoteId = url.searchParams.get('quoteId');
state.quoteId = quoteId;

export type ConfigProps = {
  defaults?: {
    isBillToShipping?: boolean;
    selectedShippingMethod?: Selector<ShippingMethod>;
  };
  shipping?: {
    filterOptions?: Filter<ShippingMethod>;
  };
  features?: {
    b2b?: {
      quotes?: boolean;
      routeLogin?: () => string | void;
    };
  };
  langDefinitions?: typeof definition & { default: { Checkout: any } };
  models?: {
    CartModel?: Model<CartModel>;
    CustomerModel?: Model<CustomerModel>;
    EstimateShippingModel?: Model<ShippingMethod[]>;
  };
};

export const initialize = new Initializer<ConfigProps>({
  init: async (_config = {}) => {
    initialize.config.setConfig(
      deepmerge(
        {
          defaults: {
            isBillToShipping: true,
            selectedShippingMethod: (options) => {
              return options.length > 0 ? options[0] : null;
            },
          },
          features: {
            b2b: { quotes: false },
          },
        },
        _config
      )
    );
  },
  listeners: addCheckoutEventListeners,
});

export const config = initialize.config;
