import {
  setPaymentMethodOnCartMutation,
  setPaymentMethodOnQuoteMutation,
} from '@/checkout/api/setPaymentMethod/graphql';
import { PaymentMethodInput as PaymentMethodInputModel } from '@/checkout/data/models';
import {
  transformCart,
  transformNegotiableQuote,
  transformPaymentMethodInputModelToCartInput,
  transformPaymentMethodInputModelToQuoteInput,
} from '@/checkout/data/transforms';
import { dispatchApiCall } from '@/checkout/lib/dispatchApiCall';
import { QueueName } from '@/checkout/lib/enqueueRequest';
import { MissingPaymentMethod } from '@/checkout/lib/errors/customErrors';
import { ensureHasCartOrQuoteId } from '@/checkout/lib/guards';
import { state } from '@/checkout/lib/state';

const createPaymentMethodSetter = <TTransformedInput, TTransformedOutput>(
  entityId: string,
  entityKey: string,
  mutation: string,
  transformer: (data: any) => TTransformedOutput,
  transformInput: (input: PaymentMethodInputModel) => TTransformedInput,
  path: string
) => {
  return async (
    input: PaymentMethodInputModel
  ): Promise<TTransformedOutput> => {
    return await dispatchApiCall({
      type: 'mutation',
      query: mutation,
      options: {
        variables: {
          [entityKey]: entityId,
          input: transformInput(input),
        },
      },
      path,
      queueName: QueueName.Updates,
      transformer,
    });
  };
};

const ensureHasPaymentMethodCode = (input: PaymentMethodInputModel) => {
  if (!input.code) {
    throw new MissingPaymentMethod();
  }
};

export const setPaymentMethod = async (input: PaymentMethodInputModel) => {
  ensureHasCartOrQuoteId();
  ensureHasPaymentMethodCode(input);

  const isCart = Boolean(state.cartId);

  const setter = isCart
    ? createPaymentMethodSetter(
        state.cartId!,
        'cartId',
        setPaymentMethodOnCartMutation,
        transformCart,
        transformPaymentMethodInputModelToCartInput,
        'setPaymentMethodOnCart.cart'
      )
    : createPaymentMethodSetter(
        state.quoteId!,
        'quoteId',
        setPaymentMethodOnQuoteMutation,
        transformNegotiableQuote,
        transformPaymentMethodInputModelToQuoteInput,
        'setNegotiableQuotePaymentMethod.quote'
      );

  return await setter(input);
};
