import { GetStoreConfigQuery } from '@/checkout/__generated__/types';
import { STORE_CONFIG_DEFAULTS } from '@/checkout/api/getStoreConfig';
import { StoreConfig, TaxDisplay } from '@/checkout/data/models';

export function transformTaxDisplay(data: number | null | undefined) {
  switch (data) {
    case 1:
      return TaxDisplay.EXCLUDING_TAX;
    case 2:
      return TaxDisplay.INCLUDING_TAX;
    case 3:
      return TaxDisplay.INCLUDING_EXCLUDING_TAX;
    default:
      return TaxDisplay.EXCLUDING_TAX;
  }
}

export function transformStoreConfig(
  data: GetStoreConfigQuery['storeConfig']
): StoreConfig {
  if (!data) return STORE_CONFIG_DEFAULTS;

  const {
    default_country,
    is_checkout_agreements_enabled,
    shopping_cart_display_shipping,
  } = data;

  return {
    defaultCountry: default_country || STORE_CONFIG_DEFAULTS.defaultCountry,
    agreementsEnabled: is_checkout_agreements_enabled,
    shoppingCartDisplaySetting: {
      shipping: transformTaxDisplay(shopping_cart_display_shipping),
    },
  };
}
