import {
  setShippingMethodsOnCartMutation,
  setShippingMethodsOnQuoteMutation,
} from '@/checkout/api/setShippingMethods/graphql';
import { ShippingMethodInput as ShippingMethodInputModel } from '@/checkout/data/models/api';
import {
  transformCart,
  transformNegotiableQuote,
  transformShippingMethodsInputModel,
} from '@/checkout/data/transforms';
import { dispatchApiCall } from '@/checkout/lib/dispatchApiCall';
import { QueueName } from '@/checkout/lib/enqueueRequest';
import { MissingShippingMethod } from '@/checkout/lib/errors/customErrors';
import { ensureHasCartOrQuoteId } from '@/checkout/lib/guards';
import { state } from '@/checkout/lib/state';

const createShippingMethodsSetter = <TTransformedOutput>(
  entityId: string,
  entityKey: string,
  mutation: string,
  transformer: (data: any) => TTransformedOutput,
  path: string
) => {
  return async (
    input: Array<ShippingMethodInputModel>
  ): Promise<TTransformedOutput> => {
    return await dispatchApiCall({
      type: 'mutation',
      query: mutation,
      queueName: QueueName.Updates,
      options: {
        variables: {
          [entityKey]: entityId,
          shippingMethods: transformShippingMethodsInputModel(input),
        },
      },
      path,
      transformer,
    });
  };
};

const ensureIsValidInput = (input: Array<ShippingMethodInputModel>) => {
  if (!Array.isArray(input) || input.length === 0) {
    throw new MissingShippingMethod();
  }
};

export const setShippingMethods = async (
  input: Array<ShippingMethodInputModel>
) => {
  ensureHasCartOrQuoteId();
  ensureIsValidInput(input);

  const isCart = Boolean(state.cartId);

  const setter = isCart
    ? createShippingMethodsSetter(
        state.cartId!,
        'cartId',
        setShippingMethodsOnCartMutation,
        transformCart,
        'setShippingMethodsOnCart.cart'
      )
    : createShippingMethodsSetter(
        state.quoteId!,
        'quoteId',
        setShippingMethodsOnQuoteMutation,
        transformNegotiableQuote,
        'setNegotiableQuoteShippingMethods.quote'
      );

  return await setter(input);
};
